mapper.select:
SELECT c.id, c.article_id, c.root_id, c.parent_username, c.content, c.content_html,
       c.user_id, c.location, c.user_agent_os, c.user_agent_browser,
       c.is_approved, c.is_admin_reply, c.create_time, a.title AS article_title
FROM article_comments c
LEFT JOIN articles a ON c.article_id = a.id


        AND c.article_id = #{dto.articleId}


        AND c.is_approved = #{dto.isApproved}


        AND c.create_time >= #{dto.startTime}


        AND c.create_time <= #{dto.endTime}


ORDER BY c.create_time DESC
